pg_prewarm 忘れがちだが、テーブルだけではなくインデックスも対象に出来る
create extension pg_prewarm;SELECTpg_prewarm('t1', 'buffer', 'main'),pg_prewarm('t2_delta', 'buffer', 'main'),pg_prewarm('t1_PKEY', 'buffer', 'main');  pg_buffercache create extension pg_buffercache;select c.relname, count(*) as buffersfrom pg_buffercache as binner join pg_class as c on b.relfilenode = pg_relation_filenode(c.oid) and b.reldatabase in (0, (select oid from pg_database where datname = current_database()))group by c.relnameorder by 2 descLIMIT 30; 実行ログ postgres=&gt; SELECTpostgres-&gt; pg_prewarm('t1', 'buffer', 'main')postgres-&gt; ,pg_prewarm('t2_delta', 'buffer', 'main')postgres-&gt; ,pg_prewarm('t1_PKEY', 'buffer', 'main')postgres-&gt; ; pg_prewarm | pg_prewarm | pg_prewarm ------------+------------+------------1818182 | 909091 | 54840(1 row)postgres=&gt; select c.relname, count(*) as bufferspostgres-&gt; from pg_buffercache as bpostgres-&gt; inner join pg_class as c on b.relfilenode = pg_relation_filenode(c.oid) and b.reldatabase in (0, (select oid from pg_database where datname = current_database()))postgres-&gt; group by c.relnamepostgres-&gt; order by 2 descpostgres-&gt; LIMIT 30;relname | buffers -----------------------------------+---------t1 | 1818687t2_delta | 909091t1_idx | 426172t1_pkey | 54840pg_attribute | 60pg_toast_2619 | 36pg_class | 13pg_proc | 12pg_statistic | 11pg_attribute_relid_attnum_index | 9pg_proc_oid_index | 8pg_proc_proname_args_nsp_index | 6pg_amop | 6pg_class_relname_nsp_index | 5pg_amproc | 4pg_operator | 4pg_class_oid_index | 4pg_statistic_relid_att_inh_index | 4pg_index | 4pg_amop_opr_fam_index | 4pg_operator_oid_index | 4pg_type | 3pg_amop_fam_strat_index | 3pg_type_oid_index | 3pg_operator_oprname_l_r_n_index | 3pg_amproc_fam_proc_index | 3pg_depend_reference_index | 3pg_type_typname_nsp_index | 3pg_auth_members_member_role_index | 2pg_cast_source_target_index | 2(30 rows)postgres=&gt;

はじめに 一定のテストデータ、及び多少の負荷が掛かるSQLをRedshift Spectrumに向けて実行したい場合の作業用メモ。
データ確認 データはs3://awssampledbuswest2/ssbgz/から自バケットに予めコピーしている
aws s3 ls --human-readable --recursive s3://ssbgz-spectrum/  [ec2-user@bastin ~]$ aws s3 ls --human-readable --recursive s3://ssbgz-spectrum/ 2021-06-15 16:10:10 100.5 MiB customer/customer0002_part_00.gz 2021-06-15 16:10:10 24.6 KiB dwdate/dwdate.tbl.gz 2021-06-15 16:10:10 3.1 GiB lineorder/lineorder0000_part_00.gz 2021-06-15 16:10:10 3.1 GiB lineorder/lineorder0001_part_00.gz 2021-06-15 16:10:11 3.1 GiB lineorder/lineorder0002_part_00.gz 2021-06-15 16:10:10 3.1 GiB lineorder/lineorder0003_part_00.gz 2021-06-15 16:10:14 3.1 GiB lineorder/lineorder0004_part_00.gz 2021-06-15 16:11:47 3.1 GiB lineorder/lineorder0005_part_00.gz 2021-06-15 16:12:16 3.1 GiB lineorder/lineorder0006_part_00.gz 2021-06-15 16:12:26 3.1 GiB lineorder/lineorder0007_part_00.gz 2021-06-15 16:12:35 8.3 MiB part/part0000_part_00.gz 2021-06-15 16:12:36 8.3 MiB part/part0001_part_00.gz 2021-06-15 16:12:38 8.3 MiB part/part0002_part_00.gz 2021-06-15 16:12:39 8.3 MiB part/part0003_part_00.gz 2021-06-15 16:12:40 32.5 MiB supplier/supplier.tbl_0000_part_00.gz 2021-06-15 16:12:42 20 Bytes supplier/supplier0001_part_00.gz 2021-06-15 16:12:42 20 Bytes supplier/supplier0002_part_00.gz 2021-06-15 16:12:42 20 Bytes supplier/supplier0003_part_00.gz  外部スキーマ定義 create external schema s3 from data catalog database 's3_spectrum' iam_role 'arn:aws:iam::xxxxxxxxxxx:role/myRedshiftRole' create external database if not exists;  mydb=# create external schema s3 from data catalog mydb-# database 's3_spectrum' mydb-# iam_role 'arn:aws:iam::xxxxxxxxxxx:role/myRedshiftRole' mydb-# create external database if not exists; INFO: External database &quot;s3_spectrum&quot; already exists CREATE SCHEMA  外部表の定義 drop table s3.part; CREATE EXTERNAL TABLE s3.part ( p_partkey INTEGER, p_name VARCHAR(22), p_mfgr VARCHAR(6), p_category VARCHAR(7), p_brand1 VARCHAR(9), p_color VARCHAR(11), p_type VARCHAR(25), p_size INTEGER, p_container VARCHAR(10)) row format delimited fields terminated by '|' stored as textfile LOCATION 's3://ssbgz-spectrum/part/'; drop table s3.supplier; CREATE EXTERNAL TABLE s3.supplier ( s_suppkey INTEGER, s_name VARCHAR(25), s_address VARCHAR(25), s_city VARCHAR(10), s_nation VARCHAR(15), s_region VARCHAR(12), s_phone VARCHAR(15)) row format delimited fields terminated by '|' stored as textfile LOCATION 's3://ssbgz-spectrum/supplier/'; drop table s3.customer; CREATE EXTERNAL TABLE s3.customer ( c_custkey INTEGER, c_name VARCHAR(25), c_address VARCHAR(25), c_city VARCHAR(10), c_nation VARCHAR(15), c_region VARCHAR(12), c_phone VARCHAR(15), c_mktsegment VARCHAR(10)) row format delimited fields terminated by '|' stored as textfile LOCATION 's3://ssbgz-spectrum/customer/'; drop table s3.dwdate; CREATE EXTERNAL TABLE s3.dwdate ( d_datekey INTEGER, d_date VARCHAR(19), d_dayofweek VARCHAR(10), d_month VARCHAR(10), d_year INTEGER, d_yearmonthnum INTEGER, d_yearmonth VARCHAR(8), d_daynuminweek INTEGER, d_daynuminmonth INTEGER, d_daynuminyear INTEGER, d_monthnuminyear INTEGER, d_weeknuminyear INTEGER, d_sellingseason VARCHAR(13), d_lastdayinweekfl VARCHAR(1), d_lastdayinmonthfl VARCHAR(1), d_holidayfl VARCHAR(1), d_weekdayfl VARCHAR(1)) row format delimited fields terminated by '|' stored as textfile LOCATION 's3://ssbgz-spectrum/dwdate/'; drop table s3.lineorder; CREATE EXTERNAL TABLE s3.lineorder ( lo_orderkey INTEGER, lo_linenumber INTEGER, lo_custkey INTEGER, lo_partkey INTEGER, lo_suppkey INTEGER, lo_orderdate INTEGER, lo_orderpriority VARCHAR(15), lo_shippriority VARCHAR(1), lo_quantity INTEGER, lo_extendedprice INTEGER, lo_ordertotalprice INTEGER, lo_discount INTEGER, lo_revenue INTEGER, lo_supplycost INTEGER, lo_tax INTEGER, lo_commitdate INTEGER, lo_shipmode VARCHAR(10)) row format delimited fields terminated by '|' stored as textfile LOCATION 's3://ssbgz-spectrum/lineorder/';  テストクエリ SELECT c_city, s_city, d_year, SUM(lo_revenue) AS revenue FROM s3.customer, s3.lineorder, s3.supplier, s3.dwdate WHERE lo_custkey = c_custkey AND lo_suppkey = s_suppkey AND lo_orderdate = d_datekey AND (c_city='UNITED KI1' OR c_city='UNITED KI5') AND (s_city='UNITED KI1' OR s_city='UNITED KI5') AND d_yearmonth = 'Dec1997' GROUP BY c_city, s_city, d_year ORDER BY d_year ASC, revenue DESC;

表領域使用率を確認するSQL
set pages 2000 lin 2000col name for a15SELECT t.tablespace_name name, t.status, t.contents type, t.extent_management extmgt, t.allocation_type alloc, t.initial_extent/1024 init_kb, t.segment_space_management segmgt, TO_CHAR(NVL(d.bytes - NVL(f.bytes, 0), 0)/1024/1024,'9,999,990.9') &quot;USED(MB)&quot;, TO_CHAR(NVL(d.bytes, 0)/1024/1024, '9,999,990.9') &quot;TOTAL(MB)&quot;, TO_CHAR(NVL(d.bytes - NVL(f.bytes, 0), 0)/(NVL(d.bytes, -1)/100),'990.0') &quot;USED(%)&quot;FROM dba_tablespaces t, (SELECT tablespace_name, SUM(bytes) bytes FROM dba_data_filesGROUP BY tablespace_name) d, (SELECT tablespace_name, SUM(bytes) bytes FROM dba_free_spaceGROUP BY tablespace_name) fWHERE t.tablespace_name = d.tablespace_name(+)AND t.tablespace_name = f.tablespace_name(+)AND NOT (t.extent_management = 'LOCAL' AND t.contents = 'TEMPORARY')UNION ALLSELECT t.tablespace_name name, t.status, t.contents type, t.extent_management extmgt, t.allocation_type alloc, t.initial_extent/1024 init_kb, t.segment_space_management segmgt, TO_CHAR(NVL(f.bytes, 0)/1024/1024, '9,999,990.9') &quot;USED(MB)&quot;, TO_CHAR(NVL(d.bytes, 0)/1024/1024, '9,999,990.9') &quot;TOTAL(MB)&quot;, TO_CHAR(NVL(f.bytes/(d.bytes/100), 0), '990.0') &quot;USED(%)&quot;FROM dba_tablespaces t, (SELECT tablespace_name, SUM(bytes) bytes FROM dba_temp_filesGROUP BY tablespace_name) d, (SELECT tablespace_name, SUM(bytes_cached) bytes FROMv$temp_extent_pool GROUP BY tablespace_name) fWHERE t.tablespace_name = d.tablespace_name(+)AND t.tablespace_name = f.tablespace_name(+)AND t.extent_management = 'LOCAL' AND t.contents = 'TEMPORARY'ORDER BY name; 結果
